/* AI Reality Check — Page Loader
   Applies saved theme preference before page renders to prevent flash. */
(function () {
  try {
    var saved = localStorage.getItem('arc-theme');
    if (saved === 'dark') {
      document.documentElement.classList.add('theme-dark');
    } else if (saved === 'light') {
      document.documentElement.classList.add('theme-light');
    }
  } catch (e) {}
})();
